+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'auto'}
+	| {type: 'fr'; fraction: number; min: number};
+
+type Placement = {
+	node: DOMElement;
+	columnStart: number;
+	columnEnd: number;
+	rowStart: number;
+	rowEnd: number;
+};
+
+const gridSizedNodes = new WeakSet<DOMElement>();
+const gridItems = new WeakSet<DOMElement>();
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') {
+		return {type: 'auto'};
+	}
+
+	const fraction = /^(\\d*\\.?\\d+)fr$/.exec(value);
+	if (fraction) {
+		return {type: 'fr', fraction: Number(fraction[1]), min: 0};
+	}
+
+	const minmax = /^minmax\\((\\d+(?:\\.\\d+)?),\\s*(\\d+(?:\\.\\d+)?|\\d*\\.?\\d+fr)\\)$/.exec(value);
+	if (minmax) {
+		const minimum = Number(minmax[1]);
+		const maximum = minmax[2];
+		const maximumFraction = /^(\\d*\\.?\\d+)fr$/.exec(maximum);
+		return maximumFraction
+			? {type: 'fr', fraction: Number(maximumFraction[1]), min: minimum}
+			: {type: 'fixed', size: Number(maximum)};
+	}
+
+	const size = Number(value);
+	return Number.isFinite(size) && size >= 0 ? {type: 'fixed', size} : {type: 'auto'};
+};
+
+const parseTracks = (template: string | undefined): Track[] =>
+	(template?.match(/minmax\\([^)]*\\)|\\S+/g) ?? ['auto']).map(parseTrack);
+
+const parseLine = (value: number | string | undefined): [number, number] | undefined => {
+	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
+		return [value - 1, value];
+	}
+
+	if (typeof value !== 'string') {
+		return;
+	}
+
+	const lines = value.split('/').map(part => Number(part.trim()));
+	if (lines.length === 2 && lines.every(line => Number.isInteger(line) && line > 0)) {
+		return [lines[0] - 1, lines[1] - 1];
+	}
+};
+
+const getGap = (node: DOMElement, direction: 'column' | 'row'): number =>
+	direction === 'column'
+		? (node.style.columnGap ?? node.style.gap ?? 0)
+		: (node.style.rowGap ?? node.style.gap ?? 0);
+
+const placeItems = (
+	children: DOMElement[],
+	columnCount: number,
+	rowCount: number,
+): {placements: Placement[]; rowCount: number; columnCount: number} => {
+	const occupied = new Set<string>();
+	const placements: Placement[] = [];
+	let columns = columnCount;
+	let rows = rowCount;
+
+	const fits = (columnStart: number, columnEnd: number, rowStart: number, rowEnd: number) => {
+		for (let row = rowStart; row < rowEnd; row++) {
+			for (let column = columnStart; column < columnEnd; column++) {
+				if (occupied.has(`${row}:${column}`)) return false;
+			}
+		}
+		return true;
+	};
+
+	const occupy = (placement: Placement) => {
+		columns = Math.max(columns, placement.columnEnd);
+		rows = Math.max(rows, placement.rowEnd);
+		for (let row = placement.rowStart; row < placement.rowEnd; row++) {
+			for (let column = placement.columnStart; column < placement.columnEnd; column++) {
+				occupied.add(`${row}:${column}`);
+			}
+		}
+		placements.push(placement);
+	};
+
+	for (const node of children) {
+		const column = parseLine(node.style.gridColumn);
+		const row = parseLine(node.style.gridRow);
+		if (column && row) {
+			occupy({node, columnStart: column[0], columnEnd: column[1], rowStart: row[0], rowEnd: row[1]});
+			continue;
+		}
+
+		const columnSpan = column ? column[1] - column[0] : 1;
+		const rowSpan = row ? row[1] - row[0] : 1;
+		let rowStart = row?.[0] ?? 0;
+		let columnStart = column?.[0] ?? 0;
+		while (!fits(columnStart, columnStart + columnSpan, rowStart, rowStart + rowSpan)) {
+			if (column) {
+				rowStart++;
+			} else if (row) {
+				columnStart++;
+			} else if (++columnStart + columnSpan > columns) {
+				columnStart = 0;
+				rowStart++;
+			}
+		}
+
+		occupy({node, columnStart, columnEnd: columnStart + columnSpan, rowStart, rowEnd: rowStart + rowSpan});
+	}
+
+	return {placements, rowCount: rows, columnCount: columns};
+};
+
+const sizeTracks = (
+	tracks: Track[],
+	available: number,
+	gap: number,
+	autoSizes: number[],
+): number[] => {
+	const sizes = tracks.map((track, index) =>
+		track.type === 'fixed' ? track.size : track.type === 'auto' ? autoSizes[index] : track.min,
+	);
+	const remaining = Math.max(0, available - gap * Math.max(0, tracks.length - 1) - sizes.reduce((sum, size) => sum + size, 0));
+	const totalFractions = tracks.reduce((sum, track) => sum + (track.type === 'fr' ? track.fraction : 0), 0);
+	return sizes.map((size, index) =>
+		tracks[index].type === 'fr' && totalFractions > 0
+			? size + (remaining * tracks[index].fraction) / totalFractions
+			: size,
+	);
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	for (const child of node.childNodes) {
+		layoutGrid(child);
+	}
