+	if (node.style.display !== 'grid' || !node.yogaNode) return;
+
+	const children = node.childNodes.filter(child => child.yogaNode && child.style.display !== 'none');
+	let columns = parseTracks(node.style.gridTemplateColumns);
+	let rows = parseTracks(node.style.gridTemplateRows);
+	const placed = placeItems(children, columns.length, rows.length);
+	columns = [...columns, ...Array.from({length: placed.columnCount - columns.length}, () => ({type: 'auto'} as const))];
+	rows = [...rows, ...Array.from({length: placed.rowCount - rows.length}, () => ({type: 'auto'} as const))];
+
+	const columnGap = getGap(node, 'column');
+	const rowGap = getGap(node, 'row');
+	const columnAutoSizes = Array<number>(columns.length).fill(0);
+	const rowAutoSizes = Array<number>(rows.length).fill(0);
+	for (const placement of placed.placements) {
+		if (placement.columnEnd - placement.columnStart === 1) {
+			columnAutoSizes[placement.columnStart] = Math.max(columnAutoSizes[placement.columnStart], placement.node.yogaNode!.getComputedWidth());
+		}
+		if (placement.rowEnd - placement.rowStart === 1) {
+			rowAutoSizes[placement.rowStart] = Math.max(rowAutoSizes[placement.rowStart], placement.node.yogaNode!.getComputedHeight());
+		}
+	}
+
+	const width = node.yogaNode.getComputedWidth();
+	const height = node.yogaNode.getComputedHeight();
+	const columnSizes = sizeTracks(columns, width, columnGap, columnAutoSizes);
+	const naturalHeight = rowAutoSizes.reduce((sum, size) => sum + size, 0) + rowGap * Math.max(0, rows.length - 1);
+	const rowSizes = sizeTracks(rows, node.style.height === undefined ? naturalHeight : height, rowGap, rowAutoSizes);
+
+	if (node.style.height === undefined) {
+		node.yogaNode.setHeight(rowSizes.reduce((sum, size) => sum + size, 0) + rowGap * Math.max(0, rows.length - 1));
+		gridSizedNodes.add(node);
+	}
+
+	for (const placement of placed.placements) {
+		const yogaNode = placement.node.yogaNode!;
+		const left = columnSizes.slice(0, placement.columnStart).reduce((sum, size) => sum + size, 0) + columnGap * placement.columnStart;
+		const top = rowSizes.slice(0, placement.rowStart).reduce((sum, size) => sum + size, 0) + rowGap * placement.rowStart;
+		const itemWidth = columnSizes.slice(placement.columnStart, placement.columnEnd).reduce((sum, size) => sum + size, 0) + columnGap * (placement.columnEnd - placement.columnStart - 1);
+		const itemHeight = rowSizes.slice(placement.rowStart, placement.rowEnd).reduce((sum, size) => sum + size, 0) + rowGap * (placement.rowEnd - placement.rowStart - 1);
+		yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		yogaNode.setPosition(Yoga.EDGE_LEFT, left);
+		yogaNode.setPosition(Yoga.EDGE_TOP, top);
+		yogaNode.setWidth(itemWidth);
+		yogaNode.setHeight(itemHeight);
+		gridItems.add(placement.node);
+	}
+};
+
+export const applyGridLayout = (rootNode: DOMElement): void => {
+	layoutGrid(rootNode);
+};
